CREATE TABLE name (
);

CREATE TABLE workflows (
  workflow_id                         TEXT                 PRIMARY KEY,
  title                               TEXT                ,
  description                         TEXT                ,
  created                             TIMESTAMPTZ         ,
  modified                            TIMESTAMPTZ         ,
  identifier                          TEXT                
);
COMMENT ON TABLE workflows IS 'Table: Workflows';
COMMENT ON COLUMN workflows.title IS 'Human-readable name for the workflow. Maps to dct:title per Dublin Core.';
COMMENT ON COLUMN workflows.description IS 'Detailed description of the workflow purpose and scope. Maps to dct:description per Dublin Core.';
COMMENT ON COLUMN workflows.created IS 'Date the workflow was created. Maps to dct:created per Dublin Core.';
COMMENT ON COLUMN workflows.modified IS 'Date the workflow was last modified. Maps to dct:modified. Used to identify stale workflows per NTWF CQ5.';
COMMENT ON COLUMN workflows.identifier IS 'External reference identifier (e.g., ticket number). Maps to dct:identifier. Join key to operational systems.';

CREATE TABLE workflow_steps (
  workflow_step_id                    TEXT                 PRIMARY KEY,
  label                               TEXT                ,
  sequence_position                   INTEGER             ,
  requires_human_approval             BOOLEAN             ,
  is_step_of                          TEXT                ,
  assigned_role                       TEXT                ,
  precedes_steps                      TEXT                ,
  precedes_steps_2                    TEXT                ,
  approval_gates                      TEXT                
);
COMMENT ON TABLE workflow_steps IS 'Table: WorkflowSteps';
COMMENT ON COLUMN workflow_steps.label IS 'Human-readable name for the step. Maps to rdfs:label.';
COMMENT ON COLUMN workflow_steps.sequence_position IS 'Ordinal position in workflow sequence. Maps to ntwf:sequencePosition (functional). Supports positional ordering queries.';
COMMENT ON COLUMN workflow_steps.requires_human_approval IS 'Whether this step requires a human agent. Maps to ntwf:requiresHumanApproval. Answers NTWF CQ3.';
COMMENT ON COLUMN workflow_steps.is_step_of IS 'Parent workflow containing this step. Inverse of WorkflowSteps. Maps to ntwf:isStepOf.';
COMMENT ON COLUMN workflow_steps.assigned_role IS 'Role responsible for this step. Maps to ntwf:assignedRole (functional). Implements role-agent separation.';

CREATE TABLE approval_gates (
  approval_gate_id                    TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  description                         TEXT                ,
  workflow_step                       TEXT                ,
  escalation_threshold_hours          INTEGER             
);
COMMENT ON TABLE approval_gates IS 'Table: ApprovalGates';
COMMENT ON COLUMN approval_gates.name IS 'Display name of the approval gate. Maps to rdfs:label.';
COMMENT ON COLUMN approval_gates.description IS 'Description of what this gate approves and its criteria.';
COMMENT ON COLUMN approval_gates.workflow_step IS 'The workflow step that this gate is attached to. Establishes double-typing.';
COMMENT ON COLUMN approval_gates.escalation_threshold_hours IS 'Hours that may elapse before delegation chain activates. Maps to ntwf:escalationThresholdHours.';

CREATE TABLE roles (
  role_id                             TEXT                 PRIMARY KEY,
  label                               TEXT                ,
  comment                             TEXT                ,
  department                          TEXT                ,
  filled_by                           TEXT                ,
  workflow_steps                      TEXT                ,
  delegates_to                        TEXT                ,
  delegated_to_by                     TEXT                
);
COMMENT ON TABLE roles IS 'Table: Roles';
COMMENT ON COLUMN roles.label IS 'Human-readable name for the role. Maps to rdfs:label.';
COMMENT ON COLUMN roles.comment IS 'Description of the role''s responsibilities. Maps to rdfs:comment.';
COMMENT ON COLUMN roles.department IS 'Department that owns this role. Maps to org:memberOf.';
COMMENT ON COLUMN roles.filled_by IS 'Agent currently filling this role. Maps to ntwf:filledBy. The change-management triple - update this when personnel change.';
COMMENT ON COLUMN roles.workflow_steps IS 'Steps assigned to this role. Inverse of AssignedRole.';
COMMENT ON COLUMN roles.delegates_to IS 'Role to escalate to when this role''s agent is unavailable. Maps to ntwf:delegatesTo. Enables delegation chain queries.';
COMMENT ON COLUMN roles.delegated_to_by IS 'Inverse of DelegatesTo. Role that delegates to this role.';

CREATE TABLE agents (
  agent_id                            TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  type_of_agent                       TEXT                ,
  roles                               TEXT                ,
  description                         TEXT                ,
  model_version                       TEXT                ,
  mbox                                TEXT                ,
  artifacts                           TEXT                ,
  datasets                            TEXT                
);
COMMENT ON TABLE agents IS 'Table: Agents';
COMMENT ON COLUMN agents.name IS 'Full name of the person. Maps to foaf:name per FOAF ontology.';
COMMENT ON COLUMN agents.roles IS 'Roles filled by this agent. Inverse of FilledBy.';
COMMENT ON COLUMN agents.mbox IS 'Email address of the person. Maps to foaf:mbox per FOAF ontology. Used for contact and identity resolution.';

CREATE TABLE artifacts (
  artifact_id                         TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  description                         TEXT                ,
  produced_by                         TEXT                ,
  sequence_position                   INTEGER             
);
COMMENT ON TABLE artifacts IS 'Table: Artifacts';
COMMENT ON COLUMN artifacts.name IS 'Display name of the artifact. Maps to rdfs:label.';
COMMENT ON COLUMN artifacts.description IS 'Description of the artifact''s content and purpose.';
COMMENT ON COLUMN artifacts.produced_by IS 'Workflow step that produces this artifact. Maps to ntwf:producedBy.';
COMMENT ON COLUMN artifacts.sequence_position IS 'Position in the artifact provenance chain.';

CREATE TABLE precedes_steps (
  precedes_step_id                    TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  from_step                           TEXT                ,
  to_step                             TEXT                
);
COMMENT ON TABLE precedes_steps IS 'Table: PrecedesSteps';
COMMENT ON COLUMN precedes_steps.from_step IS 'The step that comes BEFORE (source of the precedes edge).';
COMMENT ON COLUMN precedes_steps.to_step IS 'The step that comes AFTER (target of the precedes edge).';

CREATE TABLE datasets (
  dataset_id                          TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  description                         TEXT                ,
  processed_by                        TEXT                ,
  time_period                         TEXT                
);
COMMENT ON TABLE datasets IS 'Table: Datasets';
COMMENT ON COLUMN datasets.name IS 'Display name of the dataset. Maps to dct:title.';
COMMENT ON COLUMN datasets.description IS 'Description of the dataset''s content and source.';
COMMENT ON COLUMN datasets.processed_by IS 'AI agent that processes this dataset. Inverse of ProcessesDatasets.';
COMMENT ON COLUMN datasets.time_period IS 'Time period the dataset covers (e.g., ''Q1 2026'').';

CREATE TABLE departments (
  department_id                       TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  description                         TEXT                ,
  roles                               TEXT                ,
  count_of_roles                      INTEGER             ,
  roles_2                             TEXT                
);
COMMENT ON TABLE departments IS 'Table: Departments';
COMMENT ON COLUMN departments.name IS 'Human-readable name of the department. Maps to rdfs:label.';
COMMENT ON COLUMN departments.description IS 'Description of the department''s function and responsibilities.';
COMMENT ON COLUMN departments.roles IS 'Roles owned by this department. Inverse of Department on Roles.';
COMMENT ON COLUMN departments.count_of_roles IS 'Count of roles owned by this department.';

CREATE TABLE types_of_agents (
  types_of_agent_id                   TEXT                 PRIMARY KEY,
  name                                TEXT                ,
  description                         TEXT                
);
COMMENT ON TABLE types_of_agents IS 'Table: TypesOfAgents';
COMMENT ON COLUMN types_of_agents.name IS 'Display name of the AI agent. Maps to schema:name.';
COMMENT ON COLUMN types_of_agents.description IS 'Description of the AI agent''s purpose and capabilities.';

